SELECT *
FROM iot_notification_delivery
WHERE tenant_id = #{tenantId}
  AND id = #{id}
  AND is_delete = 0
LIMIT 1

SELECT *
FROM iot_notification_delivery
WHERE tenant_id = #{tenantId}
  AND is_delete = 0

  AND status = #{status}


  AND channel_id = #{channelId}


  AND subscription_id = #{subscriptionId}

ORDER BY id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM iot_notification_delivery
WHERE tenant_id = #{tenantId}
  AND is_delete = 0

  AND status = #{status}


  AND channel_id = #{channelId}


  AND subscription_id = #{subscriptionId}
